      }
    }

    return { success: true, failedFindings, reviewUrl };
  }, { prNumber, dryRun });
}

function formatReviewBody(result: ReviewResult, generalFindings: Finding[]): string {
  const statusEmoji =
    result.status === "pass"
      ? ":white_check_mark:"
      : result.status === "fail"
