  const severityEmoji = SEVERITY_EMOJI[finding.severity] || "";
  const statusEmoji = STATUS_EMOJI[finding.status] || "";

  return [
    `### ${severityEmoji} ${finding.requirement}`,
    `**Status:** ${statusEmoji} ${finding.status} | **Severity:** ${finding.severity}`,
    "",
    finding.details,
  ].join("\n");
}

